"use client";

import { useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { useLocale, useTranslations } from "next-intl";
import { useCartContext } from "@/contexts/CartContext";
import { useProfile } from "@/hooks/useProfile";
import { buildImageUrl } from "@/lib/utils";
import MainLayout from "@/components/MainLayout";

function usePlaceholderSrc() {
  return (
    "data:image/svg+xml;utf8," +
    encodeURIComponent(
      `<svg xmlns='http://www.w3.org/2000/svg' width='100' height='100' viewBox='0 0 100 100' fill='none'><rect width='100' height='100' rx='8' fill='%23f8fafc'/><rect x='10' y='10' width='80' height='80' rx='6' fill='white' stroke='%23e2e8f0'/><text x='50' y='55' text-anchor='middle' fill='%2394a3b8' font-family='Arial' font-size='12'>No img</text></svg>`
    )
  );
}

export default function CartPage() {
  const locale = useLocale();
  const t = useTranslations("Cart");
  const tCommon = useTranslations("Common");
  const tCheckout = useTranslations("Checkout");
  const placeholderSrc = usePlaceholderSrc();

  const {
    items,
    summary,
    isEmpty,
    isLoading,
    updateItem,
    removeItem,
    clearCart,
    isUpdatingItem,
    isRemovingItem,
    isClearingCart,
    grandTotal,
    itemCount,
  } = useCartContext();

  const { data: profile } = useProfile();
  const [usePoints, setUsePoints] = useState(false);
  const [pointsToUse, setPointsToUse] = useState(0);

  const formatPrice = (value: number) =>
    value.toLocaleString(locale === "vi" ? "vi-VN" : "en-US", {
      minimumFractionDigits: 0,
    });

  const isMutating = isUpdatingItem || isRemovingItem || isClearingCart;

  const handleClearCart = async () => {
    if (window.confirm(t("clearConfirm"))) {
      await clearCart();
    }
  };

  return (
    <MainLayout>
      <div className="mx-auto max-w-6xl px-3 py-4 sm:px-4 sm:py-6">
        {/* Breadcrumb */}
        <nav className="mb-4 text-sm text-slate-500 sm:mb-6">
          <Link href={`/${locale}`} className="hover:text-primary">
            {tCommon("home")}
          </Link>
          <span className="mx-2">/</span>
          <span className="text-slate-900">
            {t("title")}
          </span>
        </nav>

        <h1 className="mb-4 text-xl font-bold text-slate-900 sm:mb-6 sm:text-2xl">
          {t("yourCart")}
          {itemCount > 0 && (
            <span className="ml-2 text-base font-normal text-slate-500 sm:text-lg">
              ({itemCount} {tCommon("items")})
            </span>
          )}
        </h1>

        {isLoading ? (
          <div className="flex h-64 items-center justify-center rounded-xl border border-slate-200 bg-white">
            <div className="text-slate-500">
              {t("loading")}
            </div>
          </div>
        ) : isEmpty ? (
          <div className="flex h-64 flex-col items-center justify-center rounded-xl border border-slate-200 bg-white text-center">
            <svg
              className="mb-4 h-20 w-20 text-slate-300"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={1}
                d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z"
              />
            </svg>
            <p className="mb-4 text-lg text-slate-600">
              {t("empty")}
            </p>
            <Link
              href={`/${locale}`}
              className="rounded-xl bg-primary px-6 py-2.5 font-semibold text-white transition hover:bg-primary-dark"
            >
              {t("continueShopping")}
            </Link>
          </div>
        ) : (
          <div className="grid gap-4 sm:gap-6 lg:grid-cols-3">
            {/* Cart Items */}
            <div className="lg:col-span-2">
              <div className="rounded-xl border border-slate-200 bg-white">
                {/* Header */}
                <div className="flex items-center justify-between border-b border-slate-200 px-3 py-2.5 sm:px-4 sm:py-3">
                  <span className="font-semibold text-slate-900">
                    {t("products")}
                  </span>
                  <button
                    type="button"
                    onClick={handleClearCart}
                    disabled={isMutating}
                    className="text-sm text-red-500 hover:text-red-600 disabled:opacity-50"
                  >
                    {t("clearAll")}
                  </button>
                </div>

                {/* Items */}
                <div className="divide-y divide-slate-100">
                  {items.map((item) => {
                    const imageSrc = item.productImage
                      ? buildImageUrl(item.productImage)
                      : placeholderSrc;

                    return (
                      <div key={item.id} className="flex gap-3 p-3 sm:gap-4 sm:p-4">
                        {/* Image */}
                        <Link
                          href={`/${locale}/products/${item.productId}`}
                          className="relative h-20 w-20 flex-shrink-0 overflow-hidden rounded-lg bg-slate-50 sm:h-24 sm:w-24"
                        >
                          <Image
                            src={imageSrc}
                            alt={item.productName || "Product"}
                            fill
                            sizes="(min-width: 640px) 96px, 80px"
                            className="object-contain p-1"
                            unoptimized
                            onError={(e) => {
                              (e.target as HTMLImageElement).src = placeholderSrc;
                            }}
                          />
                        </Link>

                        {/* Info */}
                        <div className="flex flex-1 flex-col">
                          <Link
                            href={`/${locale}/products/${item.productId}`}
                            className="line-clamp-2 font-medium text-slate-800 hover:text-primary"
                          >
                            {item.productName}
                          </Link>

                          {/* Options */}
                          {item.options && item.options.length > 0 && (
                            <div className="mt-1 text-sm text-slate-500">
                              {item.options
                                .map((opt) => `${opt.typeName}: ${opt.value}`)
                                .join(", ")}
                            </div>
                          )}

                          {/* SKU */}
                          {item.variantSku && (
                            <div className="mt-1 text-xs text-slate-400">
                              SKU: {item.variantSku}
                            </div>
                          )}

                          {/* Discount tag */}
                          {item.activeSaleOff > 0 && (
                            <div className="mt-1 flex flex-wrap items-center gap-1.5">
                              <span className="inline-flex items-center rounded bg-red-500 px-2 py-0.5 text-xs font-bold text-white">
                                {t("discountLabel")} {formatPrice(item.activeSaleOff)}đ
                              </span>
                              {item.quantity > 1 && (
                                <span className="text-xs text-green-600 font-medium">
                                  × {item.quantity} = -{formatPrice(item.activeSaleOff * item.quantity)}đ
                                </span>
                              )}
                            </div>
                          )}

                          {/* Price tier info */}
                          {item.appliedTier && (
                            <div className="mt-1 text-sm text-green-600">
                              {t("bulkPrice")} ({item.appliedTier.minQty}+)
                            </div>
                          )}

                          <div className="mt-auto flex flex-wrap items-end justify-between gap-2 pt-2 sm:pt-3">
                            {/* Unit price */}
                            <div className="flex flex-col">
                              {item.activeSaleOff > 0 && (
                                <span className="text-sm text-slate-400 line-through">
                                  {formatPrice(item.unitPrice)} đ
                                </span>
                              )}
                              <span className="text-base font-semibold text-primary sm:text-lg">
                                {formatPrice(item.unitPrice - item.activeSaleOff)} đ
                              </span>
                            </div>

                            {/* Quantity controls */}
                            <div className="flex items-center gap-1.5 sm:gap-2">
                              <div className="flex items-center rounded-lg border border-slate-200">
                                <button
                                  type="button"
                                  onClick={() =>
                                    updateItem(item.id, Math.max(1, item.quantity - 1))
                                  }
                                  disabled={isMutating || item.quantity <= 1}
                                  className="flex h-9 w-9 items-center justify-center text-slate-600 hover:bg-slate-50 disabled:opacity-40"
                                >
                                  −
                                </button>
                                <span className="w-8 text-center text-sm font-medium sm:w-10">
                                  {item.quantity}
                                </span>
                                <button
                                  type="button"
                                  onClick={() => updateItem(item.id, item.quantity + 1)}
                                  disabled={isMutating || item.quantity >= item.stock}
                                  className="flex h-9 w-9 items-center justify-center text-slate-600 hover:bg-slate-50 disabled:opacity-40"
                                >
                                  +
                                </button>
                              </div>
                              <button
                                type="button"
                                onClick={() => removeItem(item.id)}
                                disabled={isMutating}
                                className="flex h-9 w-9 items-center justify-center rounded-lg text-slate-400 hover:bg-red-50 hover:text-red-500 disabled:opacity-40"
                                aria-label="Remove item"
                              >
                                <svg
                                  className="h-5 w-5"
                                  fill="none"
                                  viewBox="0 0 24 24"
                                  stroke="currentColor"
                                >
                                  <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth={2}
                                    d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                                  />
                                </svg>
                              </button>
                            </div>
                          </div>

                          {/* Line total */}
                          <div className="mt-2 text-right text-sm">
                            <span className="text-slate-500">
                              {t("subtotalLabel")}{" "}
                            </span>
                            <span className="font-medium text-slate-700">
                              {formatPrice(item.lineTotal)} đ
                            </span>
                            {item.activeSaleOff > 0 && (
                              <span className="ml-1.5 text-green-600 font-medium">
                                (-{formatPrice(item.activeSaleOff * item.quantity)}đ)
                              </span>
                            )}
                          </div>

                          {/* Stock warning */}
                          {item.quantity >= item.stock && (
                            <div className="mt-1 text-right text-xs text-amber-600">
                              {t("stockWarning", { count: item.stock })}
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* Summary */}
            <div className="lg:col-span-1">
              <div className="sticky top-20 rounded-xl border border-slate-200 bg-white p-3 sm:p-4 lg:top-4">
                <h2 className="mb-4 text-lg font-semibold text-slate-900">
                  {tCheckout("orderSummary")}
                </h2>

                {summary && (
                  <div className="space-y-3 text-sm">
                    <div className="flex justify-between text-slate-600">
                      <span>
                        {t("subtotal")} ({summary.totalQuantity} {tCommon("items")})
                      </span>
                      <span>{formatPrice(summary.subtotal)} đ</span>
                    </div>

                    {summary.saleOffDiscount > 0 && (
                      <div className="flex justify-between text-green-600">
                        <span>{t("discount")}</span>
                        <span>-{formatPrice(summary.saleOffDiscount)} đ</span>
                      </div>
                    )}

                    {summary.bundleDiscount > 0 && (
                      <div className="flex justify-between text-green-600">
                        <span>{t("bundleDiscount")}</span>
                        <span>-{formatPrice(summary.bundleDiscount)} đ</span>
                      </div>
                    )}

                    {summary.giftValue > 0 && (
                      <div className="flex justify-between text-green-600">
                        <span>{t("giftValue")}</span>
                        <span>-{formatPrice(summary.giftValue)} đ</span>
                      </div>
                    )}

                    {/* Points display - Shopee style */}
                    {profile && profile.point > 0 && (
                      <div className="space-y-2 py-1">
                        <div className="flex items-center justify-between">
                          <label className="flex cursor-pointer items-center gap-2">
                            <input
                              type="checkbox"
                              checked={usePoints}
                              onChange={(e) => {
                                setUsePoints(e.target.checked);
                                if (!e.target.checked) setPointsToUse(0);
                              }}
                              className="h-4 w-4 rounded border-slate-300 text-primary focus:ring-primary"
                            />
                            <svg
                              className="h-4 w-4 text-amber-500"
                              viewBox="0 0 24 24"
                              fill="currentColor"
                            >
                              <circle cx="12" cy="12" r="10" fill="currentColor" />
                              <text
                                x="12"
                                y="16"
                                textAnchor="middle"
                                fontSize="12"
                                fontWeight="bold"
                                fill="white"
                              >
                                P
                              </text>
                            </svg>
                            <span className="text-slate-600">
                              {t("points.use")}
                            </span>
                          </label>
                          <span className="text-xs text-slate-500">
                            {t("points.available")}: {formatPrice(profile.point)}
                          </span>
                        </div>
                        {usePoints && (
                          <div className="flex items-center gap-2">
                            <input
                              type="number"
                              min={0}
                              max={Math.min(profile.point, grandTotal)}
                              value={pointsToUse || ""}
                              onChange={(e) => {
                                const val = Math.max(0, Math.min(
                                  Number(e.target.value),
                                  Math.min(profile.point, grandTotal)
                                ));
                                setPointsToUse(val);
                              }}
                              placeholder="0"
                              className="w-24 rounded-lg border border-slate-200 px-2 py-1.5 text-sm focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                            />
                            <button
                              type="button"
                              onClick={() => setPointsToUse(Math.min(profile.point, grandTotal))}
                              className="text-xs text-primary hover:underline"
                            >
                              {t("points.useAll")}
                            </button>
                          </div>
                        )}
                      </div>
                    )}

                    {/* Points discount row */}
                    {usePoints && pointsToUse > 0 && (
                      <div className="flex justify-between text-green-600">
                        <span>{t("points.deduction")}</span>
                        <span>-{formatPrice(pointsToUse)} đ</span>
                      </div>
                    )}

                    <div className="border-t border-slate-200 pt-3">
                      <div className="flex justify-between text-base font-semibold text-slate-900">
                        <span>{t("total")}</span>
                        <span className="text-xl text-primary">
                          {formatPrice(Math.max(0, grandTotal - (usePoints ? pointsToUse : 0)))} đ
                        </span>
                      </div>
                      <p className="mt-1 text-xs text-slate-500">
                        {t("shippingNote")}
                      </p>
                    </div>
                  </div>
                )}

                <div className="mt-6 space-y-3">
                  <Link
                    href={`/${locale}/checkout`}
                    className="block w-full rounded-xl bg-primary py-3 text-center font-semibold text-white transition hover:bg-primary-dark"
                  >
                    {t("checkout")}
                  </Link>
                  <Link
                    href={`/${locale}`}
                    className="block w-full rounded-xl border border-slate-200 py-3 text-center font-semibold text-slate-700 transition hover:bg-slate-50"
                  >
                    {t("continueShopping")}
                  </Link>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </MainLayout>
  );
}
